mapper.select:
SELECT a.id, a.warehouse_id as warehouseId, a.goods_id as goodsId, a.goods_name as goodsName, a.sku_id as skuId, a.sku_code as skuCode, a.sku_name as skuName, a.alert_qty as alertQty, COALESCE(s.usable_num, 0) as currentQty, a.status, a.create_by as createBy, a.create_time as createTime, a.update_by as updateBy, a.update_time as updateTime, a.remark FROM erp_warehouse_goods_stock_alert a LEFT JOIN erp_warehouse_goods_stock s ON a.goods_id = s.goods_id WHERE a.status = 1
AND a.warehouse_id = #{warehouseId}
ORDER BY a.create_time DESC
